          "body": {
            "version": 1,
            "nodes": [
              {
                "type": "paragraph",
                "text": "Before you invest in hardware, you must ensure your chosen site will be profitable. New vending operators should focus on validating demand to minimize risk."
              },
              {
                "type": "list",
                "style": "bullet",
                "items": [
                  "Analyze foot traffic patterns at the location.",
                  "Determine the average dwell time of visitors.",
                  "Evaluate existing food and beverage options nearby."
                ]
              }
            ]
          }
        }
